#include<bits/stdc++.h>
using namespace std;
vector<pair<int,int>> mp[1010];
int n,m,siz[1010],dp[1010][1010];
void dfs(int x,int fa=-1)
{
    siz[x]=1;
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa)
        {
            dp[v][1]=val;
            dfs(v,x);
            siz[x]+=siz[v];
            for(int j=siz[x];j>=1;j--)
            {
                for(int k=1;k<=siz[v]&&k<j;k++)
                {
                    dp[x][j]=max(dp[x][j],dp[x][j-k]+dp[v][k]);
                }
            }
        }
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        int k,s;
        scanf("%d%d",&k,&s);
        dp[i][1]=s;
        mp[k].push_back(make_pair(i,s));
    }
    dfs(0);
    printf("%d",dp[0][m+1]);
    return 0;
}
